import{_ as p,r as t,o as l,c as o,a as n,b as a,d as r,w as d,e as i}from"./chunks/framework.8tiMeCK-.js";const y=JSON.parse('{"title":"7.6  利用控制台设备捕获中断上下文中的崩溃日志","description":"","frontmatter":{},"headers":[],"relativePath":"notes/linux_kernel_debugging/ch07_6.md","filePath":"notes/linux_kernel_debugging/ch07_6.md","lastUpdated":null}'),h={name:"notes/linux_kernel_debugging/ch07_6.md"};function c(k,s,g,u,b,m){const e=t("IRQ");return l(),o("div",null,[s[5]||(s[5]=n(`<h1 id="_7-6-利用控制台设备捕获中断上下文中的崩溃日志" tabindex="-1">7.6 利用控制台设备捕获中断上下文中的崩溃日志 <a class="header-anchor" href="#_7-6-利用控制台设备捕获中断上下文中的崩溃日志" aria-label="Permalink to &quot;7.6  利用控制台设备捕获中断上下文中的崩溃日志&quot;">​</a></h1><p>上一节我们给手里的工具箱又加了几件利器——从栈空间检查到源码定位脚本。你可能会觉得，有了这些，哪怕内核崩溃我也能把它按在地上摩擦。</p><p>先别太自信。</p><p>之前的测试环境其实有点「温室」的味道：不管是直接 <code>insmod</code> 触发，还是通过工作队列触发，我们的 Oops 都发生在<strong>进程上下文</strong>里。这意味着什么呢？意味着内核还有机会「体面地」报错，把堆栈信息打印到屏幕上，甚至可能还能让你再敲几条命令。</p><p>但在真实世界里，很多棘手的崩溃发生在一个更加危险的地方——<strong>中断上下文</strong>。</p><p>那里没有进程可以责怪，没有退路，而且——如果运气不好——连屏幕输出都会被吞没。</p><p>这一节，我们要把场景推向极端：在硬中断处理函数里亲手制造一个崩溃，然后看看当系统死机、键盘失灵、连 <code>dmesg</code> 都敲不出来的时候，我们该如何拿到那个救命的诊断日志。</p><hr><h3 id="暴走的中断上下文" tabindex="-1">暴走的中断上下文 <a class="header-anchor" href="#暴走的中断上下文" aria-label="Permalink to &quot;暴走的中断上下文&quot;">​</a></h3><p>我们准备了一个新的测试模块 <code>oops_inirqv3</code>。它的逻辑很简单粗暴：利用内核的 <code>irq_work</code> 机制，把一个函数注册到中断上下文中去执行。</p><p>这里简单回顾一下（我们在上一章内存泄漏测试里用过类似的技术）：<code>irq_work</code> 是一种特殊的异步执行机制，它保证回调函数会在中断上下文（通常是硬中断）里被执行。</p><p>来看代码：</p><div class="language-c vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// ch7/oops_inirqv3/oops_inirqv3.c</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">void</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> irq_work</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">struct</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> irq_work </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">*</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">irqwk</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    int</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> want_oops </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">    PRINT_CTX</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">();</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   // 打印当前上下文信息，让我们确信它在 IRQ 里</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    if</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">!!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">want_oops)</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> // 好了，让我们在中断里制造个事故</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        // 这一行可能导致致命死锁！</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">        *</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">int</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> *</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">0x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">100</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> =</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;x&#39;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>注意那个注释。我们手动往 <code>0x100</code> 这个地址写数据。这显然是一个非法操作（位于 NULL 陷阱页内），会触发页面异常。</p><p>现在，在你的虚拟机里加载这个模块：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/ch7/oops_inirqv3</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">make</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> insmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./oops_inirqv3.ko</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>在我的测试环境里（VirtualBox 6.1 + Ubuntu 20.04 Guest + 5.10.60 内核），回车键按下去之后，发生了一件令人绝望的事：</p><p><strong>什么都没发生。</strong></p><p>不是那种「打印了一堆报错然后卡住」，而是屏幕直接黑屏，或者光标彻底不动了。没有 Oops 信息，没有 <code>Kernel panic</code> 提示，甚至连 <code>Caps Lock</code> 键的灯都不闪烁了。</p><p>系统彻底死给你看了。</p><p>现在怎么办？<code>dmesg</code>？敲不出来的。重启？日志全丢。</p><p>这时候，作为工程师，你的直觉会告诉你：<strong>内核肯定想说话，但它想说的话没能传到显示器上。</strong> 我们需要另一条通道，一条不依赖显卡驱动的通道，把内核的遗言偷偷运出来。</p><hr><h3 id="绕道而行-虚拟串口控制台" tabindex="-1">绕道而行：虚拟串口控制台 <a class="header-anchor" href="#绕道而行-虚拟串口控制台" aria-label="Permalink to &quot;绕道而行：虚拟串口控制台&quot;">​</a></h3><p>欢迎来到真实世界。</p><p>解决这个问题的思路非常经典，虽然我们这里的操作是针对 VirtualBox 这种虚拟化环境的，但它的思想适用于几乎所有嵌入式开发板和服务器：</p><blockquote><p><strong>既然图形界面（显示器）这路断了，我们就用串口这路把日志「走私」出来。</strong></p></blockquote><p>我们要做的，是在客户机和宿主机之间建立一根「虚拟网线」——一个虚拟串口。内核会把所有 <code>printk</code> 的信息同时写到这个串口里，而串口的另一端，连着你宿主机上的一个普通文本文件。</p><h4 id="第一步-配置宿主机端的虚拟串口" tabindex="-1">第一步：配置宿主机端的虚拟串口 <a class="header-anchor" href="#第一步-配置宿主机端的虚拟串口" aria-label="Permalink to &quot;第一步：配置宿主机端的虚拟串口&quot;">​</a></h4><p>如果虚拟机还在跑，先把它关机。</p><p>打开 Oracle VirtualBox 的管理界面，选中你的虚拟机，点「设置」齿轮图标。</p><ol><li>在左侧菜单找到 <strong>「串口」</strong>。</li><li>勾选 <strong>「启用端口 1」</strong>。</li><li><strong>端口模式</strong>：选择 <strong>「Raw File」</strong>（原始文件）。这意味着数据会被直接写入一个文件，而不是别的网络流或物理设备。</li><li><strong>路径/地址</strong>：填入你宿主机上的一个文件路径。比如我的 Linux 宿主机上，我填的是 <code>/home/user/console_lkd.txt</code>。</li></ol><p>配置好大概是这个样子（见书中图 7.21）。点 OK 保存。</p><h4 id="第二步-告诉内核使用这个控制台" tabindex="-1">第二步：告诉内核使用这个控制台 <a class="header-anchor" href="#第二步-告诉内核使用这个控制台" aria-label="Permalink to &quot;第二步：告诉内核使用这个控制台&quot;">​</a></h4><p>现在启动虚拟机。但在内核真正跑起来之前，我们需要劫持一下启动参数。</p><ol><li>启动时狂按 <code>Shift</code> 键，打断 GRUB 引导过程，进入菜单。</li><li>找到 <strong>「Advanced options for Ubuntu」</strong>，选里面那个我们要测试的自定义内核（5.10.60-prod01）。</li><li>按 <code>e</code> 键编辑启动项。</li><li>找到以 <code>linux /boot/vmlinuz-...</code> 开头的那一行。</li></ol><p>这就是我们要动手脚的地方。把光标移到这一行的末尾，加上这一串参数：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>console=ttyS0 console=tty0 ignore_loglevel</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这里的 <code>ttyS0</code> 就是我们的串口设备。<code>console=ttyS0</code> 告诉内核「把控制台输出重定向到串口」，<code>console=tty0</code> 保留屏幕输出。<code>ignore_loglevel</code> 则是那句老话：「把所有东西都吐出来，别管什么日志级别了，我全都要」。</p><p>改完之后，按 <code>Ctrl + X</code> 启动系统。</p><hr><h3 id="验证通道与捕获崩溃" tabindex="-1">验证通道与捕获崩溃 <a class="header-anchor" href="#验证通道与捕获崩溃" aria-label="Permalink to &quot;验证通道与捕获崩溃&quot;">​</a></h3><p>进入系统后，先别急着加载模块。我们得先确认这条「走私通道」是通的。</p><p><strong>验证串口输出</strong></p><p>在虚拟机里，以 root 身份执行这句：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># echo &quot;testing serial console 1 2 3&quot; &gt; /dev/kmsg</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这一刻，神奇的事情发生了。</p><p>切换到你的宿主机，打开你刚才指定的那个日志文件（比如 <code>~/console_lkd.txt</code>）。你应该能看到刚才那行字已经躺在里面了：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>$ tail -n1 ~/console_lkd.txt</span></span>
<span class="line"><span>[  646.403129] testing serial console 1 2 3</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>通道通了。现在，即使前方是万丈深渊，我们也有一根安全绳了。</p><p><strong>再次触发崩溃</strong></p><p>回到虚拟机，再次加载那个狠心模块：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">..</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/ch7/oops_inirqv3</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> insmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./oops_inirqv3.ko</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>正如预期的那样，虚拟机瞬间僵住，界面死锁。</p><p>别管它了。回到宿主机，打开那个日志文件。</p><blockquote><p><strong>胜利时刻</strong></p><p>虽然虚拟机的屏幕像死了一样漆黑一片，但在宿主机的文本文件里，内核已经把它想说的话全都说清楚了（见书中图 7.23）。</p></blockquote><p>你会看到完整的 Oops 堆栈信息，清晰得令人感动。</p><hr><h3 id="深入诊断-中断上下文的堆栈指纹" tabindex="-1">深入诊断：中断上下文的堆栈指纹 <a class="header-anchor" href="#深入诊断-中断上下文的堆栈指纹" aria-label="Permalink to &quot;深入诊断：中断上下文的堆栈指纹&quot;">​</a></h3><p>拿到日志只是第一步，接下来是侦探时间。</p><p>仔细看这次的 Oops 输出，它和之前在进程上下文里触发的崩溃有几个非常关键的区别。</p><p><strong>1. RIP 指针的指向</strong></p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>RIP: 0010:irq_work+0x18/0x20 [oops_inirqv3]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>RIP 直接指向了我们的 <code>irq_work</code> 函数。这证实了崩溃确实发生在我们设定的中断回调里。</p><p><strong>2. 双重堆栈</strong></p><p>这是最精彩的部分。你会发现这次的 Call Trace（调用栈）被分成了两截，中间有一个明显的标记：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;IRQ&gt;</span></span>
<span class="line"><span>irq_work+0x18/0x20 [oops_inirqv3]</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>&lt;/IRQ&gt;</span></span>
<span class="line"><span>...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>在 x86_64 这种现代架构上，中断处理是使用独立的<strong>中断栈</strong>的。</p>`,68)),a("ul",null,[a("li",null,[a("strong",null,[r(e,null,{default:d(()=>[...s[0]||(s[0]=[i(" ... ",-1)])]),_:1})]),s[1]||(s[1]=i("：这段区域记录的是中断发生时的执行路径。它是从中断入口开始的，这就是 ",-1)),s[2]||(s[2]=a("code",null,"irq_work",-1)),s[3]||(s[3]=i(" 所在的地方。",-1))]),s[4]||(s[4]=a("li",null,[a("strong",null,"下方部分"),i("：这是被中断打断的进程原本的堆栈。")],-1))]),s[6]||(s[6]=n('<p>我们以<strong>自底向上</strong>的顺序读这个堆栈。你会发现，内核原本正在执行某个进程的任务（可能是 <code>insmod</code>，也可能是 idle 线程），然后突然被打断，切入了中断栈，执行了我们的代码，然后——啪，挂了。</p><p><strong>3. 真正的「凶手」是谁？</strong></p><p>注意 Oops 输出里的这一行：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>CPU: 1 PID: 1699 Comm: insmod Tainted: G           OE     5.10.60-prod01 #6</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这里的 PID 是 1699，进程名是 <code>insmod</code>。</p><p>如果你的直觉是「啊，是 insmod 进程搞坏了内核」，那你在这个特定的案例里就<strong>错了</strong>。</p><p>还记得我们在上一章说的吗？在中断上下文里，<code>current</code> 宏指向的是<strong>倒霉蛋</strong>——也就是恰好当时正在跑的那个进程。它只是一个无辜的路人，被我们的硬中断「骑脸」了。代码虽然是它触发的（<code>insmod</code> 导致模块加载，进而注册了 <code>irq_work</code>），但执行崩溃指令的那一刻，CPU 其实是在替 <code>irq_work</code> 卖命，而不是替 <code>insmod</code>。</p><p>这也解释了为什么有时候你在 Oops 日志里看到的进程是 <code>swapper</code>（PID 0，也就是 idle 线程）。那是 CPU 正在发呆呢，突然来了个中断把 CPU 拉起来干活，结果活儿没干好，把 CPU 干崩了。<code>swapper</code> 纯属背锅。</p><p><strong>4. 系统为什么会死机？</strong></p><p>日志的最后，通常会有一行这样的提示：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Kernel panic - not syncing: Fatal exception in interrupt</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这就解释了为什么你的键盘会彻底失灵。内核发现——「糟糕，我在处理中断的时候崩了，这属于不可恢复的错误，为了保证数据安全，我还是自尽吧。」于是它触发了 panic，系统停止一切调度。</p><hr><h3 id="写在最后与预告" tabindex="-1">写在最后与预告 <a class="header-anchor" href="#写在最后与预告" aria-label="Permalink to &quot;写在最后与预告&quot;">​</a></h3><p>这种利用串口控制台「导出」日志的方法，是嵌入式开发者和内核工程师的必修课。</p><p>而在物理机上，这种思路演变成了一种更灵活的网络工具——<strong>netconsole</strong>。它不需要物理串口线，而是通过 UDP 包把内核日志广播到局域网里的另一台机器上。</p><p>下一节，我们将把战场从 x86 虚拟机迁移到一台真正的 ARM 设备（树莓派）上，去看看异构架构下的 Oops 是什么样的，以及如何用 netconsole 这种「无线调试」手段来搞定它。</p>',17))])}const E=p(h,[["render",c]]);export{y as __pageData,E as default};
